Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWFilaImpressao-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&FiUsuCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Solicitante") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FiUsuCod EndIf
If not (&FIempCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Empresa") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FIempCod EndIf
If not (&FIsts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Sts.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = '' do Case Case &FIsts.ToString().Trim() = "P" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "PENDENTE"
Case &FIsts.ToString().Trim() = "F" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "FINALIZADO"
Case &FIsts.ToString().Trim() = "C" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "CANCELADO/ERRO"
EndCase EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'FIDTAEMS' &FiDtaEms1.FromString(&GridStateDynamicFilter.Value) &FiDtaEms_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaEms1.IsEmpty() OR not &FiDtaEms_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FiDtaEms1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = " - " &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FiDtaEms_To1 EndIf Case &DynamicFiltersSelector1 = !'FIDTAINI' &FiDtaIni1.FromString(&GridStateDynamicFilter.Value) &FiDtaIni_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaIni1.IsEmpty() OR not &FiDtaIni_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta Inicio" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FiDtaIni1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = " - " &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FiDtaIni_To1 EndIf Case &DynamicFiltersSelector1 = !'FIDTAFIM' &FiDtaFim1.FromString(&GridStateDynamicFilter.Value) &FiDtaFim_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaFim1.IsEmpty() OR not &FiDtaFim_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta Fim" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FiDtaFim1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = " - " &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FiDtaFim_To1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'FIDTAEMS' &FiDtaEms2.FromString(&GridStateDynamicFilter.Value) &FiDtaEms_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaEms2.IsEmpty() OR not &FiDtaEms_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FiDtaEms2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = " - " &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FiDtaEms_To2 EndIf Case &DynamicFiltersSelector2 = !'FIDTAINI' &FiDtaIni2.FromString(&GridStateDynamicFilter.Value) &FiDtaIni_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaIni2.IsEmpty() OR not &FiDtaIni_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta Inicio" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FiDtaIni2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = " - " &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FiDtaIni_To2 EndIf Case &DynamicFiltersSelector2 = !'FIDTAFIM' &FiDtaFim2.FromString(&GridStateDynamicFilter.Value) &FiDtaFim_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaFim2.IsEmpty() OR not &FiDtaFim_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta Fim" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FiDtaFim2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = " - " &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FiDtaFim_To2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'FIDTAEMS' &FiDtaEms3.FromString(&GridStateDynamicFilter.Value) &FiDtaEms_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaEms3.IsEmpty() OR not &FiDtaEms_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FiDtaEms3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = " - " &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FiDtaEms_To3 EndIf Case &DynamicFiltersSelector3 = !'FIDTAINI' &FiDtaIni3.FromString(&GridStateDynamicFilter.Value) &FiDtaIni_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaIni3.IsEmpty() OR not &FiDtaIni_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta Inicio" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FiDtaIni3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = " - " &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FiDtaIni_To3 EndIf Case &DynamicFiltersSelector3 = !'FIDTAFIM' &FiDtaFim3.FromString(&GridStateDynamicFilter.Value) &FiDtaFim_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaFim3.IsEmpty() OR not &FiDtaFim_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta Fim" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FiDtaFim3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = " - " &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FiDtaFim_To3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Cód" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Status" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "PC" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Matricial, cupom" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Mensagem" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "RELATORIO" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Pedido" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Nota" &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Inicio" &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = "Emissao"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order FIempCod FIcod (FiDtaFim) when &OrderedBy = 1 order FIcod when &OrderedBy = 2 AND &OrderedDsc = False order (FIcod) when &OrderedBy = 2 AND &OrderedDsc = True order FIsts when &OrderedBy = 3 AND &OrderedDsc = False order (FIsts) when &OrderedBy = 3 AND &OrderedDsc = True order FIimpPC when &OrderedBy = 4 AND &OrderedDsc = False order (FIimpPC) when &OrderedBy = 4 AND &OrderedDsc = True order FIimpTip when &OrderedBy = 5 AND &OrderedDsc = False order (FIimpTip) when &OrderedBy = 5 AND &OrderedDsc = True order FImsg when &OrderedBy = 6 AND &OrderedDsc = False order (FImsg) when &OrderedBy = 6 AND &OrderedDsc = True order FIrelNam when &OrderedBy = 7 AND &OrderedDsc = False order (FIrelNam) when &OrderedBy = 7 AND &OrderedDsc = True order FiPedCod when &OrderedBy = 8 AND &OrderedDsc = False order (FiPedCod) when &OrderedBy = 8 AND &OrderedDsc = True order FiNfeCod when &OrderedBy = 9 AND &OrderedDsc = False order (FiNfeCod) when &OrderedBy = 9 AND &OrderedDsc = True order FiDtaIni when &OrderedBy = 10 AND &OrderedDsc = False order (FiDtaIni) when &OrderedBy = 10 AND &OrderedDsc = True order FiDtaEms when &OrderedBy = 11 AND &OrderedDsc = False order (FiDtaEms) when &OrderedBy = 11 AND &OrderedDsc = True
using DSWWFilaImpressao(&FiUsuCod, &FIempCod, &FIsts, &DynamicFiltersSelector1, &FiDtaEms1, &FiDtaEms_To1 , &FiDtaIni1, &FiDtaIni_To1, &FiDtaFim1, &FiDtaFim_To1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2 , &FiDtaEms2, &FiDtaEms_To2, &FiDtaIni2, &FiDtaIni_To2, &FiDtaFim2, &FiDtaFim_To2 , &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &FiDtaEms3, &FiDtaEms_To3, &FiDtaIni3, &FiDtaIni_To3 , &FiDtaFim3, &FiDtaFim_To3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = FIcod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = '' do Case Case FIsts.ToString().Trim() = "P" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "PENDENTE"
Case FIsts.ToString().Trim() = "F" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "FINALIZADO"
Case FIsts.ToString().Trim() = "C" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "CANCELADO/ERRO"
EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(FIimpPC) &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(FIimpTip) &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = WWP_Export_SecureText(FImsg) &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = WWP_Export_SecureText(FIrelNam) &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Number = FiPedCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Number = FiNfeCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Date = FiDtaIni &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Date = FiDtaEms
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWFilaImpressaoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWFilaImpressaoGridState")) Else &GridState.FromXml(&Session.Get(!"WWFilaImpressaoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FIUSUCOD" &FiUsuCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FIEMPCOD" &FIempCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FISTS" &FIsts.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
